Evaluate insertion cost deltas across all eligible assigns using trial-and-rollback, then commit each order to the assign yielding minimal marginal cost increase while preserving time/sequence feasibility, with empty-assign fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := 0; jj < len(oris); jj++ {
		bestAssignIdx := -1
		bestCostDelta := 1e100
		orderId := total_ship + jj
		ori := oris[jj]
		des := dess[jj]

		candidatesStart := 0
		candidatesEnd := dispatch.AssignsLen
		if candidatesEnd == 0 {
			candidatesEnd = MAXASSIGNS
		}

		for idx := candidatesStart; idx < candidatesEnd; idx++ {
			assign := &dispatch.Assigns[idx]

			saveState := *assign

			ok := assign.AddShip(orderId, ori, des)
			if ok {
				assign.GenRoute()
				newCost := assign.Cost
				oldCost := saveState.Cost
				costDelta := newCost - oldCost

				if costDelta >= 0 && costDelta < bestCostDelta {
					bestCostDelta = costDelta
					bestAssignIdx = idx
				}
			}

			*assign = saveState
			if assign.StationsLen > 0 || idx < dispatch.AssignsLen {
				assign.GenRoute()
			}
		}

		if bestAssignIdx == -1 {
			fallbackFound := false
			for idx := candidatesStart; idx < MAXASSIGNS; idx++ {
				if idx >= dispatch.AssignsLen {
					dispatch.AssignsLen = idx + 1
				}
				assign := &dispatch.Assigns[idx]
				saveState := *assign
				ok := assign.AddShip(orderId, ori, des)
				if ok {
					assign.GenRoute()
					if assign.Cost >= 0 {
						bestAssignIdx = idx
						fallbackFound = true
						*assign = saveState
						assign.GenRoute()
						break
					}
				}
				*assign = saveState
				assign.GenRoute()
			}
			if !fallbackFound {
				lastIdx := dispatch.AssignsLen
				if lastIdx >= MAXASSIGNS {
					continue
				}
				assign := &dispatch.Assigns[lastIdx]
				assign.AddShip(orderId, ori, des)
				assign.GenRoute()
				if assign.Cost >= 0 {
					dispatch.AssignsLen++
					bestAssignIdx = lastIdx
				} else {
					assign.RemoveShip(orderId)
					assign.GenRoute()
				}
			}
		}

		if bestAssignIdx != -1 {
			finalAssign := &dispatch.Assigns[bestAssignIdx]
			finalAssign.AddShip(orderId, ori, des)
			finalAssign.GenRoute()
			if bestAssignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = bestAssignIdx + 1
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

